import struct

chunks = [b'C' + c for c in data.split(b'C') if c]

for packet in chunks:
    length = len(packet)
    
    # We target 12-byte packets as they are the most common
    if length == 12:
        try:
            # < = Little Endian
            # 2s = Header (e.g., 'CU', 'CQ')
            # H = Unsigned Short (2 bytes)
            # There are 5 'H's following the 2-byte header to make 12 bytes total
            decoded = struct.unpack('<2sHHHHH', packet)
            
            header = decoded[0].decode(errors='ignore')
            values = decoded[1:]
            
            print(f"ID: {header} | Data: {values}")
            
        except struct.error as e:
            print(f"Error unpacking 12-byte packet: {e}")
    else:
        # This will show us what the 11-byte ones look like
        print(f"Skipping packet of length {length}: {packet.hex(' ')}")
